// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;const releases = $input.all().map(item => item.json);
const total = releases.length;

const countBy = (key, value) =>
  releases.filter(r => String(r[key]).toUpperCase() === value).length;

const allBlockers = releases.flatMap(r => r.criticalBlockers || []);
const allActions = releases.flatMap(r => r.requiredActions || []);

function frequency(arr) {
  const map = {};

  for (const item of arr) {
    if (!item) continue;
    map[item] = (map[item] || 0) + 1;
  }

  return Object.entries(map)
    .sort((a, b) => b[1] - a[1])
    .map(([name, count]) => ({ name, count }));
}

function riskLevelFromScore(score) {
  const value = Number(score || 0);

  if (value >= 80) return "LOW";
  if (value >= 60) return "MEDIUM";
  return "HIGH";
}

const domainRiskBreakdown = {
  security: {
    averageScore: 0,
    riskLevel: "UNKNOWN"
  },
  performance: {
    averageScore: 0,
    riskLevel: "UNKNOWN"
  },
  business: {
    averageScore: 0,
    riskLevel: "UNKNOWN"
  },
  observability: {
    averageScore: 0,
    riskLevel: "UNKNOWN"
  },
  reliability: {
    averageScore: 0,
    riskLevel: "UNKNOWN"
  },
  compliance: {
    averageScore: 0,
    riskLevel: "UNKNOWN"
  }
};

function avg(key) {
  if (total === 0) return 0;

  return Math.round(
    releases.reduce((sum, r) => sum + Number(r[key] || 0), 0) / total
  );
}

for (const domain of Object.keys(domainRiskBreakdown)) {
  const scoreKey = `${domain}Score`;
  const averageScore = avg(scoreKey);

  domainRiskBreakdown[domain] = {
    averageScore,
    riskLevel: riskLevelFromScore(averageScore)
  };
}

const recentHighRiskReleases = releases
  .filter(r => String(r.riskLevel).toUpperCase() === "HIGH")
  .slice(0, 10)
  .map(r => ({
    releaseId: r.releaseId,
    timestamp: r.timestamp,
    releaseConfidenceScore: r.releaseConfidenceScore,
    overallRiskScore: r.overallRiskScore,
    riskLevel: r.riskLevel,
    releaseRecommendation: r.releaseRecommendation,
    criticalBlockers: r.criticalBlockers || []
  }));

const criticalRiskItems = releases.flatMap(r =>
  (r.criticalBlockers || []).map(blocker => ({
    releaseId: r.releaseId,
    timestamp: r.timestamp,
    riskLevel: r.riskLevel,
    blocker,
    recommendation: r.releaseRecommendation
  }))
);

return {
  generatedAt: new Date().toISOString(),

  summary: {
    totalReleases: total,
    totalRisks: allBlockers.length,
    highRiskReleases: countBy("riskLevel", "HIGH"),
    mediumRiskReleases: countBy("riskLevel", "MEDIUM"),
    lowRiskReleases: countBy("riskLevel", "LOW"),
    noGoReleases: countBy("releaseRecommendation", "NO_GO"),
    goWithRiskReleases: countBy("releaseRecommendation", "GO_WITH_RISK"),
    goReleases: countBy("releaseRecommendation", "GO")
  },

  domainRiskBreakdown,

  topBlockers: frequency(allBlockers).slice(0, 10),

  topRequiredActions: frequency(allActions).slice(0, 10),

  recentHighRiskReleases,

  criticalRiskItems,

  riskHeatmap: Object.entries(domainRiskBreakdown).map(([domain, data]) => ({
    domain,
    averageScore: data.averageScore,
    riskLevel: data.riskLevel
  }))
};
}

return $input.all();
